  "code": "import pandas as pd; df = pd.read_csv(\"/data/food and beverage consumption.csv\"); df['Date'] = pd.to_datetime(df['Date'], errors='coerce'); df['DayOfWeek'] = df['Date'].dt.day_name(); df = df[df['Date'].dt.year.isin([2022, 2023]) & df['Beverage Type'].str.lower().eq('beer')]; sat_avg = round(df[df.DayOfWeek.eq('Saturday')]['Total Price ($)'].mean(), 2); wed_avg = round(df[df.DayOfWeek.eq('Wednesday')]['Total Price ($)'].mean(), 2); pct_all = round((sat_avg - wed_avg) / wed_avg * 100, 1); print(\"All:\", sat_avg, wed_avg, pct_all); female_pct = round((round(df[(df.DayOfWeek.eq('Saturday')) & (df.Gender.eq('Female'))]['Total Price ($)'].mean(), 2) - round(df[(df.DayOfWeek.eq('Wednesday')) & (df.Gender.eq('Female'))]['Total Price ($)'].mean(), 2)) / round(df[(df.DayOfWeek.eq('Wednesday')) & (df.Gender.eq('Female'))]['Total Price ($)'].mean(), 2) * 100, 1); print(\"Female % change:\", female_pct); male_pct = round((round(df[(df.DayOfWeek.eq('Saturday')) & (df.Gender.eq('Male'))]['Total Price ($)'].mean(), 2) - round(df[(df.DayOfWeek.eq('Wednesday')) & (df.Gender.eq('Male'))]['Total Price ($)'].mean(), 2)) / round(df[(df.DayOfWeek.eq('Wednesday')) & (df.Gender.eq('Male'))]['Total Price ($)'].mean(), 2) * 100, 1); print(\"Male % change:\", male_pct); larger_gap_gender = 'Female' if abs(female_pct) > abs(male_pct) else 'Male'; print(\"Larger gap gender:\", larger_gap_gender)"
